const WEB3_PROVIDER_URL = process.env.WEB3_PROVIDER_URL || "";
const PRIVATE_KEY = process.env.PRIVATE_KEY || "";
const CHAIN_ID = Number(process.env.CHAIN_ID || 1);

if (!WEB3_PROVIDER_URL || !PRIVATE_KEY) {
  throw new Error("Set WEB3_PROVIDER_URL and PRIVATE_KEY environment variables.");
}

const Web3 = require("web3");
const web3 = new Web3(new Web3.providers.WebsocketProvider(WEB3_PROVIDER_URL, {
  clientConfig: {
    maxReceivedFrameSize: 100000000,
    maxReceivedMessageSize: 100000000
  },
  reconnect: {
    auto: true,
    delay: 5000,
    maxAttempts: 999999,
    onTimeout: false
  }
}));

const account = web3.eth.accounts.privateKeyToAccount(PRIVATE_KEY);
web3.eth.accounts.wallet.add(account);
web3.eth.defaultAccount = account.address;

const pendingSeen = new Set();
const MAX_TRACKED = 50000;

function trimSeen() {
  if (pendingSeen.size > MAX_TRACKED) {
    const it = pendingSeen.values();
    for (let i = 0; i < 5000; i++) {
      const v = it.next();
      if (v.done) break;
      pendingSeen.delete(v.value);
    }
  }
}

async function safeGetTransaction(hash) {
  try {
    return await web3.eth.getTransaction(hash);
  } catch {
    return null;
  }
}

async function safeEstimateGas(tx) {
  try {
    return await web3.eth.estimateGas(tx);
  } catch {
    return 21000;
  }
}

async function sendBumpTransfer(targetAddress, victimTx) {
  const latestBlock = await web3.eth.getBlock("pending");
  const baseFeePerGas = latestBlock.baseFeePerGas ? BigInt(latestBlock.baseFeePerGas) : 0n;
  const victimMaxPriority = victimTx.maxPriorityFeePerGas ? BigInt(victimTx.maxPriorityFeePerGas) : 2_000_000_000n;
  const victimMaxFee = victimTx.maxFeePerGas ? BigInt(victimTx.maxFeePerGas) : (victimTx.gasPrice ? BigInt(victimTx.gasPrice) : 20_000_000_000n);
  const priority = victimMaxPriority + 2_000_000_000n;
  const maxFee = (baseFeePerGas * 2n) + priority;
  const nonce = await web3.eth.getTransactionCount(account.address, "pending");

  const tx = {
    from: account.address,
    to: targetAddress,
    value: "0x0",
    data: "0x",
    nonce,
    chainId: CHAIN_ID,
    gas: 21000,
    maxPriorityFeePerGas: "0x" + priority.toString(16),
    maxFeePerGas: "0x" + (maxFee > victimMaxFee ? maxFee : victimMaxFee + 2_000_000_000n).toString(16),
    type: "0x2"
  };

  const signed = await web3.eth.accounts.signTransaction(tx, PRIVATE_KEY);
  return web3.eth.sendSignedTransaction(signed.rawTransaction);
}

function isInterestingVictimTx(tx) {
  if (!tx || !tx.to) return false;
  if (!tx.input || tx.input === "0x") return false;
  if (!tx.value) return true;
  try {
    return BigInt(tx.value) > 0n;
  } catch {
    return true;
  }
}

async function processPending(hash) {
  if (!hash || pendingSeen.has(hash)) return;
  pendingSeen.add(hash);
  trimSeen();

  const tx = await safeGetTransaction(hash);
  if (!isInterestingVictimTx(tx)) return;

  console.log("Potential opportunity:", {
    hash: tx.hash,
    from: tx.from,
    to: tx.to,
    gasPrice: tx.gasPrice,
    maxFeePerGas: tx.maxFeePerGas,
    maxPriorityFeePerGas: tx.maxPriorityFeePerGas,
    value: tx.value
  });

  try {
    const res = await sendBumpTransfer(tx.to, tx);
    res.on("transactionHash", h => console.log("Submitted frontrun tx:", h));
    res.on("receipt", r => console.log("Mined receipt:", r.transactionHash));
    res.on("error", e => console.error("Send error:", e.message || e));
  } catch (e) {
    console.error("Failed to submit transaction:", e.message || e);
  }
}

async function main() {
  console.log("Bot address:", account.address);
  const sub = web3.eth.subscribe("pendingTransactions");

  sub.on("data", hash => {
    processPending(hash).catch(err => console.error("Processing error:", err.message || err));
  });

  sub.on("connected", id => {
    console.log("Subscribed:", id);
  });

  sub.on("error", err => {
    console.error("Subscription error:", err.message || err);
  });

  web3.currentProvider.on("connect", () => console.log("WebSocket connected"));
  web3.currentProvider.on("error", err => console.error("WebSocket error:", err.message || err));
  web3.currentProvider.on("end", err => console.error("WebSocket ended:", err && (err.message || err)));
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});